settings.custom_liquid:
{% comment %}
  Solución para mostrar el contenido del metafield componentes_de_afeitadoras
{% endcomment %}

{% if product.metafields.custom.componentes_de_afeitadoras != blank %}
  {% assign componentes_reference = product.metafields.custom.componentes_de_afeitadoras.value %}

  {% comment %} Método para Shopify 2.0+ {% endcomment %}
  {% if componentes_reference.content != blank %}
    <div class="componentes-wrapper">
      {{ componentes_reference.content }}
    </div>

  {% comment %} Método alternativo si el anterior no funciona {% endcomment %}
  {% else %}
    {% assign page_id = product.metafields.custom.componentes_de_afeitadoras | remove: '["gid://shopify/OnlineStorePage/' | remove: '"]' %}
    {% for page in pages %}
      {% if page.id == page_id %}
        <div class="componentes-wrapper">
          {{ page.content }}
        </div>
        {% break %}
      {% endif %}
    {% endfor %}
  {% endif %}
{% endif %}

{% comment %}
  Esta es la solución para mostrar el contenido de la página referenciada
  en lugar del ID de la página
{% endcomment %}

{% if product.metafields.custom.pago != blank %}
  {% assign page_reference = product.metafields.custom.pago.value %}

  {% comment %} 
    Si estás en Shopify 2.0+, esto debería funcionar directamente 
  {% endcomment %}
  {% if page_reference.content != blank %}
    <div class="page-content-wrapper">
      {{ page_reference.content }}
    </div>

  {% comment %} 
    Solución alternativa si el método anterior no funciona 
  {% endcomment %}
  {% else %}
    {% assign page_id = product.metafields.custom.pago | remove: '["gid://shopify/OnlineStorePage/' | remove: '"]' %}
    {% for page in pages %}
      {% if page.id == page_id %}
        <div class="page-content-wrapper">
          {{ page.content }}
        </div>
        {% break %}
      {% endif %}
    {% endfor %}
  {% endif %}
{% endif %}
